1	import { useState, useEffect } from "react";
2	import { View, Text } from "@tarojs/components";
3	import Taro, { useDidShow } from "@tarojs/taro";
4	import { apiFetch, getToday, formatDate, getDomains } from "../../lib";
5	import "./index.scss";
6	
7	interface Habit {
8	  id: string;
9	  title: string;
10	  description: string | null;
11	  domainId: string;
12	  unit: string;
13	  targetValue: number;
14	  isActive: boolean;
15	  logs?: { date: string; completed: boolean; value: number }[];
16	}
17	
18	interface DailyGoal {
19	  title: string;
20	  detail: string;
21	  reason: string;
22	}
23	
24	export default function IndexPage() {
25	  const [habits, setHabits] = useState<Habit[]>([]);
26	  const [loading, setLoading] = useState(true);
27	  const [dailyGoals, setDailyGoals] = useState<DailyGoal[]>([]);
28	  const [goalsLoading, setGoalsLoading] = useState(false);
29	  const [goalsExpanded, setGoalsExpanded] = useState<Set<number>>(new Set());
30	  const [goalsDismissed, setGoalsDismissed] = useState(false);
31	
32	  useDidShow(() => {
33	    fetchHabits();
34	    checkDismissed();
35	    fetchDailyGoals();
36	  });
37	
38	  function checkDismissed() {
39	    const dismissedDate = Taro.getStorageSync("goals_dismissed_date");
40	    setGoalsDismissed(dismissedDate === getToday());
41	  }
42	
43	  async function fetchHabits() {
44	    try {
45	      const data = await apiFetch("/api/habits?date=" + getToday());
46	      setHabits(data);
47	    } catch {
48	      Taro.showToast({ title: "获取今日习惯失败", icon: "none" });
49	    }
50	    setLoading(false);
51	  }
52	
53	  async function fetchDailyGoals() {
54	    setGoalsLoading(true);
55	    try {
56	      const data = await apiFetch("/api/insights", {
57	        method: "POST",
58	        body: JSON.stringify({ type: "daily-goals" }),
59	      });
60	      setDailyGoals(data?.goals || []);
61	    } catch {
62	      setDailyGoals([]);
63	    }
64	    setGoalsLoading(false);
65	  }
66	
67	  async function toggleHabit(habitId: string) {
68	    try {
69	      await apiFetch("/api/logs", {
70	        method: "POST",
71	        body: JSON.stringify({ habitId, date: getToday() }),
72	      });
73	      fetchHabits();
74	    } catch {
75	      Taro.showToast({ title: "打卡失败", icon: "none" });
76	    }
77	  }
78	
79	  function toggleGoalExpand(idx: number) {
80	    setGoalsExpanded((prev) => {
81	      const next = new Set(prev);
82	      if (next.has(idx)) {
83	        next.delete(idx);
84	      } else {
85	        next.add(idx);
86	      }
87	      return next;
88	    });
89	  }
90	
91	  function dismissGoals() {
92	    Taro.setStorageSync("goals_dismissed_date", getToday());
93	    setGoalsDismissed(true);
94	  }
95	
96	  const completedCount = habits.filter(
97	    (h) => h.logs?.length && h.logs[0]?.completed
98	  ).length;
99	  const totalCount = habits.filter((h) => h.isActive).length;
100	  const progressPct = totalCount > 0 ? Math.round((completedCount / totalCount) * 100) : 0;
101	
102	  function renderGoalsBlock() {
103	    if (goalsDismissed) return null;
104	    if (goalsLoading) {
105	      return (
106	        <View className="goals-card">
107	          <View className="goals-header">
108	            <Text className="goals-title">📋 今日建议目标</Text>
109	          </View>
110	          <View className="skeleton-lines">
111	            <View className="skeleton-line w-80" />
112	            <View className="skeleton-line w-60" />
113	          </View>
114	        </View>
115	      );
116	    }
117	    if (!dailyGoals || dailyGoals.length === 0) return null;
118	
119	    return (
120	      <View className="goals-card">
121	        <View className="goals-header">
122	          <Text className="goals-title">📋 今日建议目标</Text>
123	          <View className="goals-dismiss" onClick={dismissGoals}>
124	            <Text>✕</Text>
125	          </View>
126	        </View>
127	        {dailyGoals.map((goal, idx) => {
128	          const expanded = goalsExpanded.has(idx);
129	          return (
130	            <View
131	              key={idx}
132	              className={`goals-item ${expanded ? "expanded" : ""}`}
133	              onClick={() => toggleGoalExpand(idx)}
134	            >
135	              <View className="goals-item-header">
136	                <Text className="goals-item-title">{goal.title}</Text>
137	                <Text className="goals-item-arrow">{expanded ? "▲" : "▼"}</Text>
138	              </View>
139	              {expanded && (
140	                <View className="goals-item-body">
141	                  <Text className="goals-item-detail">{goal.detail}</Text>
142	                  <Text className="goals-item-reason">理由：{goal.reason}</Text>
143	                </View>
144	              )}
145	            </View>
146	          );
147	        })}
148	      </View>
149	    );
150	  }
151	
152	  return (
153	    <View className="page">
154	      <Text className="header-date">{formatDate(new Date())}</Text>
155	      <Text className="header-title">今日日课</Text>
156	
157	      {renderGoalsBlock()}
158	
159	      <View className="progress-card">
160	        <View className="progress-ring">
161	          <View style={{
162	            width: "140rpx", height: "140rpx", borderRadius: "50%",
163	            background: `conic-gradient(#c4843e ${progressPct * 3.6}deg, #332e28 0deg)`,
164	            display: "flex", alignItems: "center", justifyContent: "center"
165	          }}>
166	            <View style={{
