21	export function getStreak(dates: string[]): number {
22	  const sorted = [...dates].sort().reverse();
23	  let streak = 0;
24	  const today = new Date(getToday());
25	  for (let i = 0; i < sorted.length; i++) {
26	    const expected = new Date(today);
27	    expected.setDate(expected.getDate() - i);
28	    if (sorted[i] === expected.toISOString().split("T")[0]) {
29	      streak++;
30	    } else {
31	      break;
32	    }
33	  }
34	  return streak;
35	}
