4	export async function GET(req: NextRequest) {
5	  const searchParams = req.nextUrl.searchParams;
6	  const date = searchParams.get("date");
7	
8	  const habits = store.habits.map((h) => {
9	    const log = date
10	      ? store.habitLogs.find((l: any) => l.habitId === h.id && l.date === date)
11	      : undefined;
12	    return { ...h, logs: log ? [log] : [] };
13	  });
14	
15	  return NextResponse.json(habits);
16	}
