5	const todayStr = () => new Date().toISOString().split("T")[0];
6	
7	function getRecentLogs(daysBack: number) {
8	  const logs: { date: string; completed: number; total: number }[] = [];
9	  const today = new Date();
10	  for (let i = daysBack - 1; i >= 0; i--) {
11	    const d = new Date(today);
12	    d.setDate(d.getDate() - i);
13	    const dateStr = d.toISOString().split("T")[0];
14	    const dayLogs = store.habitLogs.filter((l: any) => l.date === dateStr);
15	    logs.push({
16	      date: dateStr,
17	      completed: dayLogs.filter((l: any) => l.completed).length,
18	      total: dayLogs.length,
19	    });
20	  }
21	  return logs;
22	}
23	
24	function getHabitCompletionRates(daysBack: number) {
25	  const habits = store.habits.filter((h: any) => h.isActive);
26	  const today = new Date();
27	  return habits.map((h: any) => {
28	    let completedDays = 0;
29	    let totalDays = 0;
30	    let lastCompleted = "";
31	    for (let i = daysBack - 1; i >= 0; i--) {
32	      const d = new Date(today);
33	      d.setDate(d.getDate() - i);
34	      const dateStr = d.toISOString().split("T")[0];
35	      const log = store.habitLogs.find(
36	        (l: any) => l.habitId === h.id && l.date === dateStr
37	      );
38	      if (log) {
39	        totalDays++;
40	        if (log.completed) {
41	          completedDays++;
42	          lastCompleted = dateStr;
43	        }
44	      }
45	    }
46	    const consecutiveMiss =
47	      lastCompleted
48	        ? Math.floor(
49	            (Date.now() - new Date(lastCompleted).getTime()) /
50	              (1000 * 60 * 60 * 24)
51	          ) - 1
52	        : daysBack;
53	    return {
54	      title: h.title,
55	      domainId: h.domainId,
56	      rate: totalDays > 0 ? Math.round((completedDays / totalDays) * 100) : 0,
57	      consecutiveMiss: Math.max(0, consecutiveMiss),
58	    };
59	  });
60	}
61	
62	function getTodayLogs() {
63	  const today = todayStr();
64	  return store.habitLogs.filter((l: any) => l.date === today);
65	}
66	
67	function getStreak() {
68	  let streak = 0;
69	  const d = new Date();
70	  while (true) {
71	    const dateStr = d.toISOString().split("T")[0];
72	    const logs = store.habitLogs.filter((l: any) => l.date === dateStr);
73	    if (logs.length === 0 || logs.every((l: any) => !l.completed)) break;
74	    streak++;
75	    d.setDate(d.getDate() - 1);
76	  }
77	  return streak;
78	}
