80	function getYesterdayReview() {
81	  const d = new Date();
82	  d.setDate(d.getDate() - 1);
83	  const dateStr = d.toISOString().split("T")[0];
84	  return store.dailyReviews.find((r: any) => r.userId === "demo" && r.date === dateStr) || null;
85	}
