95	export async function POST(req: NextRequest) {
96	  const { type, data, prompt } = await req.json();
97	
98	  try {
99	    if (type === "weekly") {
100	      const habits = store.habits.filter((h: any) => h.isActive);
101	      const logs = getRecentLogs(7);
102	
103	      const message = `作为个人成长教练，根据以下本周数据给一段简短的洞察（200字以内）：
104	完成情况: ${logs.map((l) => `${l.date}: ${l.completed}/${l.total}`).join(", ")}
105	活跃习惯: ${habits.map((h: any) => h.title).join("、")}
106	指出1-2个趋势，给出1条具体改进建议。语气像帝王侍读。`;
107	
108	      const text = await getAIRecommendation(message);
109	      return NextResponse.json({ text });
110	    }
111	
112	    if (type === "review") {
113	      const message = `用户刚做了今日复盘：评分${data.score}/5，总结："${data.summary}"，亮点："${data.highlight}"，不足："${data.lowlight}"。请用帝王侍读的语气给一段鼓励+建议（100字以内）。`;
114	      const text = await getAIRecommendation(message);
115	      return NextResponse.json({ text });
116	    }
117	
118	    if (type === "generate-habits") {
119	      const message = `用户描述了以下目标："${prompt}"。请帮用户拆解成3-5个具体的每日习惯，每个习惯格式为：- [领域] 习惯名称：具体描述（目标值+单位）。直接给列表，不要多余的话。`;
120	      const text = await getAIRecommendation(message);
121	      return NextResponse.json({ text });
122	    }
123	
124	    // ---- Feature 1: AI 今日小结 (daily-summary) ----
125	    if (type === "daily-summary") {
126	      const logs = getTodayLogs();
127	      const activeHabits = store.habits.filter((h: any) => h.isActive);
128	      const totalActive = activeHabits.length;
129	      const completedCount = logs.filter((l: any) => l.completed).length;
130	      const streak = getStreak();
131	      const recentLogs = getRecentLogs(7);
132	      const yesterdayReview = getYesterdayReview();
133	      const profile = getProfile();
134	
135	      // Fallback if no data yet today
136	      if (totalActive === 0) {
137	        return NextResponse.json({
138	          text: "今日尚未打卡，完成日课后自动生成小结。",
139	        });
140	      }
141	
142	      const habitsTrend = activeHabits.map((h: any) => {
143	        const habitLogs = recentLogs.map((r) => {
144	          const log = store.habitLogs.find(
145	            (l: any) => l.habitId === h.id && l.date === r.date
146	          );
147	          return log ? log.completed : false;
148	        });
149	        return `${h.title}: [${habitLogs.map((c) => (c ? "✓" : "✗")).join(", ")}]`;
150	      }).join("\n");
151	
152	      const message = `作为天子日课（个人成长系统）的帝王侍读，根据今日数据给一段精炼的日课小结（150字以内）。
153	
154	今日完成：${completedCount}/${totalActive}
155	连续精进天数：${streak} 天
156	
157	各习惯近7日趋势：
158	${habitsTrend}
159	
160	${
161	  yesterdayReview
162	    ? `昨日复盘：
163	评分：${yesterdayReview.score}/5
164	总结：${yesterdayReview.summary || "未填写"}
165	亮点：${yesterdayReview.highlight || "未填写"}
166	不足：${yesterdayReview.lowlight || "未填写"}`
167	    : "昨日无复盘记录。"
168	}
169	
170	${
171	  profile?.goals?.length
172	    ? `用户长期目标：${profile.goals.join("、")}`
173	    : ""
174	}
175	${profile?.wakeTime ? `作息：${profile.wakeTime}起床，${profile.sleepTime || "未设"}入睡` : ""}
176	
177	语气应如帝王侍读向天子奏报——庄重而不失温度，肯定精进之处，点明可提升之处。`;
178	
179	      const text = await getAIRecommendation(message);
180	      return NextResponse.json({ text });
181	    }
182	
183	    // ---- Feature 2: AI 明日目标推荐 (daily-goals) ----
184	    if (type === "daily-goals") {
185	      // Check cache for today
186	      const td = todayStr();
187	      if (_goalCacheDate === td && _goalCache) {
188	        return NextResponse.json({ goals: _goalCache });
189	      }
190	
191	      const rates = getHabitCompletionRates(14);
192	      const yesterdayReview = getYesterdayReview();
193	      const profile = getProfile();
194	
195	      const message = `作为天子日课（个人成长系统）的帝王侍读，分析用户近14日数据，推荐1-3个今日最应关注的目标。
196	
197	各习惯完成率及断档天数：
198	${rates
199	  .map(
200	    (r) =>
201	      `${r.title}（${r.domainId}）：完成率${r.rate}%，连续${r.consecutiveMiss > 0 ? `${r.consecutiveMiss}天未完成` : "坚持中"}`
202	  )
203	  .join("\n")}
204	
205	${yesterdayReview ? `昨日复盘：评分${yesterdayReview.score}/5，总结"${yesterdayReview.summary || ""}"，亮点"${yesterdayReview.highlight || ""}"，不足"${yesterdayReview.lowlight || ""}"` : "昨日无复盘"}
206	
207	${profile?.goals?.length ? `长期目标：${profile.goals.join("、")}` : ""}
208	${profile?.wakeTime ? `作息：${profile.wakeTime}起床` : ""}
209	
210	请以JSON格式返回推荐目标数组，每个目标包含：
211	- title: 简短的标题（如"晨跑恢复"）
212	- detail: 具体建议内容（60字以内）
213	- reason: 推荐理由（40字以内）
214	
215	格式要求：只返回一个合法的JSON对象，格式为 {"goals": [{"title": "...", "detail": "...", "reason": "..."}]}，不要其他任何文字。`;
216	
217	      const raw = await getAIRecommendation(message);
218	      let goals: any[] = [];
219	      try {
220	        // Extract JSON from response (handle potential markdown wrapping)
221	        const jsonMatch = raw.match(/\{[\s\S]*\}/);
222	        if (jsonMatch) {
223	          const parsed = JSON.parse(jsonMatch[0]);
224	          goals = parsed.goals || [];
