228	      }
229	
230	      // Cache
231	      _goalCacheDate = td;
232	      _goalCache = goals;
233	
234	      return NextResponse.json({ goals });
235	    }
236	
237	    return NextResponse.json({ error: "Unknown type" }, { status: 400 });
238	  } catch (err) {
